const videos = $json.videos || [];
if (!videos.length) throw new Error('Aucune video Pexels trouvee');

const PEXELS_HOST = 'videos.pexels.com';
const MIN_DURATION = 5; // 5 secondes min
const MAX_DURATION = 60; // 60 secondes max

const extractHostname = (value) => {
  const match = String(value || '').match(/^https?:\/\/([^\/?#]+)/i);
  return match ? match[1].toLowerCase() : '';
};

const scoreVideo = (video, file) => {
  const width = Number(file.width || video.width || 0);
  const height = Number(file.height || video.height || 0);
  const duration = Number(video.duration || 0);
  const hostname = extractHostname(file.link);

  let score = 0;

  // Host preference (Pexels direct = +100)
  if (hostname === PEXELS_HOST) score += 100;
  else score += 30;

  // Portrait format (height > width)
  if (height > width) score += 50;
  else return 0; // Reject landscape

  // Resolution preference (1080x1920 ideal)
  if (width === 1080 && height === 1920) score += 150;
  else if (width === 720 && height === 1280) score += 100;
  else if (width === 540 && height === 960) score += 50;
  else if (width > 1080) score += 80;
  else if (width > 540) score += 60;
  else score += 20;

  // Duration preference (8-20 secondes = optimal)
  if (duration >= MIN_DURATION && duration <= MAX_DURATION) {
    const ideal = duration <= 15 ? 150 : duration <= 30 ? 120 : 80;
    score += ideal;
  } else return 0; // Reject too short or too long

  // File type (mp4 is standard)
  if (file.file_type === 'video/mp4') score += 40;

  return score;
};

const candidates = [];
for (const video of videos) {
  for (const file of video.video_files || []) {
    if (!file?.link) continue;
    const score = scoreVideo(video, file);
    if (score > 0) {
      candidates.push({
        link: file.link,
        width: Number(file.width || video.width || 0),
        height: Number(file.height || video.height || 0),
        duration: Number(video.duration || 0),
        photographer: video.user?.name || 'Unknown',
        score
      });
    }
  }
}

if (!candidates.length) throw new Error('Aucune video portrait de qualite trouvee');

candidates.sort((a, b) => b.score - a.score);

const selected = candidates[0];
if (selected.score < 50) throw new Error('Media quality too low (score: ' + selected.score + ')');

return [{ json: {
  id: $('Validate Input').item.json.contentIdeaId,
  workflowRunId: $('Validate Input').item.json.workflowRunId,
  topic: $('Validate Input').item.json.topic,
  script: $('Validate Input').item.json.script,
  hook: $('Validate Input').item.json.hook,
  caption: $('Validate Input').item.json.caption,
  aesthetic: $('Validate Aesthetic').item.json.aesthetic,
  background_video_url: selected.link,
  media_score: selected.score,
  media_quality: selected.score > 200 ? 'premium' : selected.score > 100 ? 'high' : 'standard',
  media_duration: selected.duration,
  media_resolution: selected.width + 'x' + selected.height
} }];

